[Fact]
public void ShouldFormatFlatPocoAsTableUsingPredefinedFormatAndConfigurableAlignment()
{
    // Arrange
    var data = new[]
    {
        new { Id = 101, Name = "ObjectA" },
        new { Id = 102, Name = "ObjectB" }
    };

    var stringWriter = new System.IO.StringWriter();
    var table = ConsoleTable.From(data)
        .Configure(o =>
        {
            o.NumberAlignment = Alignment.Right;
            o.OutputTo = stringWriter;
            o.EnableCount = false;
        });

    // Act
    table.Write(Format.Minimal);
    var output = stringWriter.ToString();

    // Assert
    Assert.Contains("Id", output);
    Assert.Contains("Name", output);
    Assert.Contains("101", output);
    Assert.Contains("ObjectA", output);
    Assert.Equal(Alignment.Right, table.Options.NumberAlignment);
    Assert.False(table.Options.EnableCount);
    Assert.DoesNotContain("Count:", output);
}

[Fact]
public void VerifyRowAdditionRequiresPredefinedColumnsAndMatchingValueCounts()
{
    // Arrange
    var table = new ConsoleTable();

    // Act & Assert: Test that rows cannot be added before columns are defined
    var missingColumnsException = Assert.Throws<Exception>(() => table.AddRow("Value 1"));
    Assert.Equal("Please set the columns first", missingColumnsException.Message);

    // Arrange: Define two columns
    table.AddColumn(new[] { "Column A", "Column B" });

    // Act & Assert: Test that row value count must match column count
    var mismatchException = Assert.Throws<Exception>(() => table.AddRow("Only One Value"));
    Assert.Contains("does not match the values", mismatchException.Message);

    // Act: Add a valid row
    table.AddRow("Valid 1", "Valid 2");

    // Assert: Verify integrity
    Assert.Equal(2, table.Columns.Count);
    Assert.Single(table.Rows);
}

[Fact]
public void ShouldWrapLongCellContentIntoMultipleSubsequentRowsToMaintainReadability()
{
    // Arrange
    // Initialize a table with a single column header.
    var table = new ConsoleTable("Description");

    // Set MaxWidth to a small value and ensure the delimiter is set to space.
    table.MaxWidth = 5;
    table.SetWordBreakDelimiter(' ');

    // Add a single row with content that exceeds MaxWidth multiple times.
    // "Part1 Part2 Part3" consists of three 5-character words separated by spaces.
    // With MaxWidth 5, it should wrap into three distinct rows to maintain word readability.
    table.AddRow("Part1 Part2 Part3");

    // Act
    // ToString calls SetFormats internally, which executes the wrapping logic.
    var result = table.ToString();

    // Assert
    // Each part should exist in the output, effectively representing subsequent rows.
    Assert.Contains("Part1", result);
    Assert.Contains("Part2", result);
    Assert.Contains("Part3", result);

    // According to the logic in SetFormats, wrapping inserts new objects into the Rows list.
    // Therefore, a single row wrapped into three parts results in a Row Count of 3.
    Assert.Contains("Count: 3", result);
}

[Fact]
public void TableShouldOptionallyIncludeTotalRowCountBasedOnConfiguration()
{
    // Arrange
    var table = new ConsoleTable("Header1", "Header2");
    table.AddRow("A1", "A2");
    table.AddRow("B1", "B2");
    table.AddRow("C1", "C2");

    // Act & Assert: Verify summary exists when EnableCount is true
    table.Configure(options => options.EnableCount = true);
    var enabledOutput = table.ToString();
    Assert.Contains("Count: 3", enabledOutput);

    // Act & Assert: Verify summary is omitted when EnableCount is false
    table.Configure(options => options.EnableCount = false);
    var disabledOutput = table.ToString();
    Assert.DoesNotContain("Count:", disabledOutput);
}

[Fact]
public void FromDictionary_ShouldGenerateTableWithKeysAsFirstColumnRowHeaders()
{
    // Arrange
    var dictionaryData = new Dictionary<string, Dictionary<string, object>>
    {
        {
            "Header_Row_1", new Dictionary<string, object>
            {
                { "Column_A", "Value_1A" },
                { "Column_B", "Value_1B" }
            }
        },
        {
            "Header_Row_2", new Dictionary<string, object>
            {
                { "Column_A", "Value_2A" },
                { "Column_B", "Value_2B" }
            }
        }
    };

    // Act
    var table = ConsoleTable.FromDictionary(dictionaryData);

    // Assert
    // The first column header should be empty as it contains the row keys
    Assert.Equal(string.Empty, table.Columns[0]);

    // Verify row headers (keys from the outer dictionary) are in the first column of each row
    Assert.Equal("Header_Row_1", table.Rows[0][0]);
    Assert.Equal("Header_Row_2", table.Rows[1][0]);

    // Verify data mapping for subsequent columns
    Assert.Equal("Value_1A", table.Rows[0][1]);
    Assert.Equal("Value_2B", table.Rows[1][2]);
}

[Fact]
public void From_ObjectCollection_AutomaticallyGeneratesColumnsFromPropertyNames()
{
    // Arrange
    // Using the 'Something' class identified in context as a POCO with Id, Name, and Date properties
    var items = new List<Something>
    {
        new Something { Id = "REF-001", Name = "Automated Test Item" }
    };

    // Act
    // Invoke the generic static method that reflects over property names
    var table = ConsoleTable.From(items);

    // Assert
    // Rule Check: Verify that column headers exactly match the property names of the collection items
    Assert.Contains("Id", table.Columns);
    Assert.Contains("Name", table.Columns);
    Assert.Contains("Date", table.Columns);

    // Ensure row values are correctly mapped to their respective columns by property index
    var idIndex = table.Columns.IndexOf("Id");
    var nameIndex = table.Columns.IndexOf("Name");

    Assert.Equal("REF-001", table.Rows[0][idIndex]);
    Assert.Equal("Automated Test Item", table.Rows[0][nameIndex]);
    Assert.Single(table.Rows);
}

[Fact]
public void TableFooterRowCountInclusionShouldBeToggleable()
{
    // Arrange
    var table = new ConsoleTable("Column 1");
    table.AddRow("Value 1");

    // Act & Assert: Verify that row count is enabled by default and present in the output
    var defaultOutput = table.ToString();
    Assert.True(table.Options.EnableCount);
    Assert.Contains("Count: 1", defaultOutput);

    // Act: Toggle the row count off using the configuration action
    table.Configure(options => options.EnableCount = false);
    var toggledOutput = table.ToString();

    // Assert: Verify that the row count is disabled and missing from the output
    Assert.False(table.Options.EnableCount);
    Assert.DoesNotContain("Count:", toggledOutput);
}

[Fact]
public void ShouldVerifyFormatsAlignmentAndUnicodeWidths()
{
    // Arrange
    // "Unicode": width 7. "测试": visual width 4 (2 per char as per context).
    // "Num": width 3. "42": width 2.
    var table = new ConsoleTable("Unicode", "Num");
    table.AddRow("测试", 42);

    table.Configure(o =>
    {
        o.NumberAlignment = Alignment.Right;
    });

    // Act
    var standardOutput = table.ToString();
    var markdownOutput = table.ToMarkDownString();
    var minimalOutput = table.ToMinimalString();

    // Assert
    // 1. Visual Width & Standard Format: Max width is 7 ("Unicode").
    // "测试" (width 4) needs 3 spaces for alignment + 1 padding = " 测试    ".
    Assert.Contains("| Unicode |", standardOutput);
    Assert.Contains("| 测试    |", standardOutput);

    // 2. Configurable Alignment & Markdown Format: Max width for "Num" is 3.
    // "42" (width 2) right-aligned in width 3 is " 42". 
    // Total column content with 1-space padding: "  42 ".
    Assert.Contains("| Unicode | Num |", markdownOutput);
    Assert.Contains("|---------|-----", markdownOutput);
    Assert.Contains("| 测试    |  42 |", markdownOutput);

    // 3. Minimal Format
    Assert.Contains("Unicode", minimalOutput);
    Assert.Contains("测试", minimalOutput);
    Assert.Contains("42", minimalOutput);
    Assert.DoesNotContain("|", minimalOutput);
}

[Fact]
public void AddRow_ShouldEnforcePriorColumnDefinitionAndValueCountAlignment()
{
    // Arrange
    var table = new ConsoleTable();

    // Act & Assert: Verify columns are required before rows can be added
    var noColumnsException = Assert.Throws<Exception>(() => table.AddRow("TestValue"));
    Assert.Equal("Please set the columns first", noColumnsException.Message);

    // Act: Define columns
    table.AddColumn(new[] { "Header1", "Header2" });

    // Act & Assert: Verify value count in row must match defined column count
    var countMismatchException = Assert.Throws<Exception>(() => table.AddRow("Value1"));
    Assert.Contains("does not match the values", countMismatchException.Message);

    // Act: Add a row with correct column count
    table.AddRow("Value1", "Value2");

    // Assert: Verify structural integrity
    Assert.Equal(2, table.Columns.Count);
    Assert.Single(table.Rows);
    Assert.Equal("Value1", table.Rows[0][0]);
    Assert.Equal("Value2", table.Rows[0][1]);
}

[Fact]
public void TableOutputTargetsShouldBeConfigurableAndDefaultToConsoleOut()
{
    // Arrange
    var table = new ConsoleTable("Column1");
    var initialOutput = table.Options.OutputTo;
    var customWriter = new StringWriter();

    // Act
    table.Configure(options => options.OutputTo = customWriter);
    var configuredOutput = table.Options.OutputTo;

    // Assert
    Assert.Equal(Console.Out, initialOutput);
    Assert.Equal(customWriter, configuredOutput);
}
